/* BLAKE2b-256 + Merkle tree in WebAssembly (Rust, wasm/blake2b/) — byte-identical to Python. Two uses:
 *  - hash(bytes): the STARK transcript / Fiat-Shamir path (~50x faster than pure-JS blake2b).
 *  - merkleCommit(values): builds the whole column Merkle tree in one wasm call (formats leaves/nodes + hashes
 *    + folds), so 8192 leaves cost 1 call instead of ~16k JS hash calls. Returns the copied layer bytes. */
const WASM_B64 = "";
let _api = null;
function _decode(b64) {
  if (typeof atob !== "undefined") return Uint8Array.from(atob(b64), (c) => c.charCodeAt(0));
  return Uint8Array.from(Buffer.from(b64, "base64"));
}
export async function initBlake2bWasm() {
  if (_api) return _api.hash;
  await _init();
  return _api.hash;
}
export async function initMerkleWasm() {
  if (!_api) await _init();
  return _api.merkle;
}
async function _init() {
  const { instance } = await WebAssembly.instantiate(_decode(WASM_B64));
  const x = instance.exports;
  const NMAX = 8192;
  const hin = x.hin_ptr(), hout = x.hout_ptr(), minp = x.min_ptr(), moutp = x.mout_ptr();
  let hinV = new Uint8Array(x.memory.buffer, hin, 16384);
  let houtV = new Uint8Array(x.memory.buffer, hout, 32);
  const minV = new BigUint64Array(x.memory.buffer, minp, NMAX);
  const moutV = new Uint8Array(x.memory.buffer, moutp, 2 * NMAX * 32);
  const hash = (bytes) => { hinV.set(bytes); x.blake2b256(hin, bytes.length, hout); return houtV.slice(0, 32); };
  // commit: write field elements to MIN, build tree in MOUT, copy the layer bytes out (MOUT is reused next call)
  const merkle = {
    NMAX,
    commit(values) {
      const n = values.length;
      for (let i = 0; i < n; i++) minV[i] = BigInt.asUintN(64, BigInt(values[i]));
      x.merkle_commit(n);
      const layers = []; let off = 0, cnt = n;
      for (;;) { layers.push({ off, cnt }); if (cnt === 1) break; off += cnt * 32; cnt >>= 1; }
      const total = off + 32;
      const bytes = moutV.slice(0, total);      // copy out (next commit overwrites MOUT)
      return { layers, bytes };
    },
  };
  _api = { hash, merkle };
}
